create table dirkspzm32.s_oet_send_bew (
    firma_nr     number(3, 0) not null enable,
    herkunft     varchar2(3 char),
    tabelle      varchar2(5 char),
    auf_id       number(*, 0),
    status       varchar2(3 char),
    aktion       varchar2(3 char),
    lte_id       varchar2(20 char),
    lhm_id       varchar2(20 char),
    lagerort     varchar2(10 char),
    menge        number(12, 3),
    ext_lief_nr  varchar2(15 char),
    ext_lief_pos varchar2(5 char),
    ist_bestand  number(*, 5),
    artikel      varchar2(30 char),
    b_datum      date,
    text         varchar2(250 char),
    err_nr       number(*, 0),
    bew_id       number(*, 0) not null enable
);

alter table dirkspzm32.s_oet_send_bew
    add constraint pk_oet_send_bew primary key ( bew_id )
        using index enable;


